+/// Add a single content document to the index writer.
+pub fn add_content_doc(
+    writer: &mut IndexWriter,
+    fields: &ContentFields,
+    doc: &ContentDoc,
+) -> Result<()> {
+    let tdoc = to_document(doc, fields);
+    writer.add_document(tdoc)?;
+    Ok(())
